mapper.insert:
INSERT INTO quick_quiz_questions (
    question, options_json, sort_order, active, created_at, updated_at
) VALUES (
    #{question}, #{optionsJson}, #{sortOrder}, #{active}, #{createdAt}, #{updatedAt}
)
ON CONFLICT(question) DO UPDATE SET
    options_json = excluded.options_json,
    sort_order = excluded.sort_order,
    active = excluded.active,
    updated_at = excluded.updated_at

mapper.select:
SELECT 
FROM quick_quiz_questions q
WHERE q.active = 1

    AND q.id NOT IN

        #{id}


AND NOT (
    EXISTS (
        SELECT 1 FROM quick_quiz_records r1
        WHERE r1.question_id = q.id AND r1.player_key = #{playerAKey}
    )
    AND EXISTS (
        SELECT 1 FROM quick_quiz_records r2
        WHERE r2.question_id = q.id AND r2.player_key = #{playerBKey}
    )
)
ORDER BY RANDOM()
LIMIT 1

SELECT COUNT(1)
FROM quick_quiz_questions q
WHERE q.active = 1

    AND q.id NOT IN

        #{id}


AND NOT (
    EXISTS (
        SELECT 1 FROM quick_quiz_records r1
        WHERE r1.question_id = q.id AND r1.player_key = #{playerAKey}
    )
    AND EXISTS (
        SELECT 1 FROM quick_quiz_records r2
        WHERE r2.question_id = q.id AND r2.player_key = #{playerBKey}
    )
)

